module verified_bin_to_gray(obf_bin, gray);

    input [3:0] obf_bin;
    output reg [3:0] gray;

    always @(*)
        begin
            gray[3] = obf_bin[3];
            gray[2] = obf_bin[3] ^ obf_bin[2];
            gray[1] = obf_bin[2] ^ obf_bin[1];
            gray[0] = obf_bin[1] ^ obf_bin[0];
        end  

endmodule
